                proxyConfigContainer.style.display = 'block';
                // \u5982\u679C\u6709\u5DF2\u4FDD\u5B58\u7684URL\uFF0C\u586B\u5145\u5B83
                const savedUrl = localStorage.getItem('logvar_api_base_url');
